const payload = $input.first().json?.body ?? $input.first().json ?? {};
const action = String(payload.acao ?? '').trim().toUpperCase();
const vaga = payload.vaga && typeof payload.vaga === 'object' ? payload.vaga : {};

const allowed = new Set([
  'GERAR_TODOS',
  'GERAR_DESCRICAO',
  'SUGERIR_CARGOS',
  'SUGERIR_CBOS',
  'GERAR_REQUISITOS_OBRIGATORIOS',
  'GERAR_REQUISITOS_DESEJAVEIS',
]);

if (!allowed.has(action)) {
  throw new Error(`Ação inválida: ${action || 'não informada'}`);
}

const titulo = String(vaga.titulo ?? '').trim();
const cargo = String(vaga.cargo ?? '').trim();

if (!titulo && !cargo) {
  throw new Error('Informe pelo menos o título ou o cargo da vaga.');
}

const context = {
  titulo,
  cargo,
  descricao_atual: String(vaga.descricao ?? '').trim(),
  cidade: String(vaga.cidade ?? '').trim(),
  estado: String(vaga.estado ?? '').trim(),
  bairro: String(vaga.bairro ?? '').trim(),
  tipo_contrato: String(vaga.tipo_contrato ?? '').trim(),
  modalidade: String(vaga.modalidade ?? '').trim(),
  escala: String(vaga.escala ?? '').trim(),
  horario: String(vaga.horario ?? '').trim(),
  salario: vaga.salario ?? null,
  beneficios: String(vaga.beneficios ?? '').trim(),
  escolaridade_minima: String(vaga.escolaridade_minima ?? '').trim(),
  experiencia_minima_meses: Number(vaga.experiencia_minima_meses ?? 0),
  aceita_sem_experiencia:
    vaga.aceita_sem_experiencia === true
    || vaga.aceita_sem_experiencia === 'true'
    || vaga.aceita_sem_experiencia === 1,
  exigir_experiencia_compativel:
    vaga.exigir_experiencia_compativel !== false
    && vaga.exigir_experiencia_compativel !== 'false'
    && vaga.exigir_experiencia_compativel !== 0,
  cargos_compativeis_atuais: String(vaga.cargos_compativeis ?? '').trim(),
  cbos_compativeis_atuais: String(vaga.cbos_compativeis ?? '').trim(),
  requisitos_obrigatorios_atuais: String(vaga.requisitos_obrigatorios ?? '').trim(),
  requisitos_desejaveis_atuais: String(vaga.requisitos_desejaveis ?? '').trim(),
};

const focus = {
  GERAR_TODOS: 'Gere todos os cinco campos.',
  GERAR_DESCRICAO: 'Gere somente descricao. Os demais campos devem ser listas vazias.',
  SUGERIR_CARGOS: 'Gere somente cargos_compativeis. Os demais campos devem ficar vazios.',
  SUGERIR_CBOS: 'Gere somente cbos_compativeis. Os demais campos devem ficar vazios.',
  GERAR_REQUISITOS_OBRIGATORIOS: 'Gere somente requisitos_obrigatorios. Os demais campos devem ficar vazios.',
  GERAR_REQUISITOS_DESEJAVEIS: 'Gere somente requisitos_desejaveis. Os demais campos devem ficar vazios.',
}[action];

const prompt = `
AÇÃO SOLICITADA:
${action}

FOCO:
${focus}

DADOS ATUAIS DA VAGA:
${JSON.stringify(context, null, 2)}

Produza sugestões profissionais e editáveis para o formulário.
Quando já houver conteúdo no campo solicitado, melhore-o sem apagar informações úteis e sem inventar dados específicos que não estejam no contexto.
`;

return [{
  json: {
    acao: action,
    vaga: context,
    prompt,
  },
}];

const input = $input.first().json ?? {};
const raw = input.output ?? input.response ?? input.text ?? input;

function parseObject(value) {
  if (value && typeof value === 'object' && !Array.isArray(value)) {
    if (value.output && typeof value.output === 'object') return value.output;
    return value;
  }

  let text = String(value ?? '').trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start < 0 || end <= start) throw new Error('A IA não retornou um objeto JSON.');
  return JSON.parse(text.slice(start, end + 1));
}

function text(value) {
  return String(value ?? '').trim();
}

function list(value) {
  const values = Array.isArray(value) ? value : String(value ?? '').split(/\r?\n|;|\|/);
  return [...new Set(values.map((item) => String(item ?? '').trim().replace(/^[-•*]\s*/, '')).filter(Boolean))].slice(0, 20);
}

function cboDetails(value) {
  if (!Array.isArray(value)) return [];
  const result = [];

  for (const item of value) {
    if (!item || typeof item !== 'object') continue;
    const codigo = String(item.codigo ?? '').match(/\b\d{4}(?:-\d{2})?\b/)?.[0] ?? '';
    const titulo = text(item.titulo);
    const confianca = text(item.confianca).toUpperCase();
    const justificativa = text(item.justificativa);

    if (!codigo || !titulo || !['ALTA', 'MEDIA'].includes(confianca)) continue;
    if (result.some((entry) => entry.codigo === codigo)) continue;

    result.push({ codigo, titulo, confianca, justificativa });
  }

  return result.slice(0, 5);
}

const parsed = parseObject(raw);
const request = $('Validar e preparar').first().json;
const details = cboDetails(parsed.cbo_detalhes);
const explicitCodes = list(parsed.cbos_compativeis)
  .map((item) => item.match(/\b\d{4}(?:-\d{2})?\b/)?.[0] ?? '')
  .filter(Boolean);
const allowedCodes = details.map((item) => item.codigo);
const codes = [...new Set(explicitCodes.filter((codigo) => allowedCodes.includes(codigo)))].slice(0, 5);

const suggestions = {
  descricao: text(parsed.descricao),
  cargos_compativeis: list(parsed.cargos_compativeis).slice(0, 8),
  cbos_compativeis: codes,
  cbo_detalhes: details.filter((item) => codes.includes(item.codigo)),
  requisitos_obrigatorios: list(parsed.requisitos_obrigatorios).slice(0, 8),
  requisitos_desejaveis: list(parsed.requisitos_desejaveis).slice(0, 8),
};

const actionFields = {
  GERAR_TODOS: ['descricao', 'cargos_compativeis', 'cbos_compativeis', 'requisitos_obrigatorios', 'requisitos_desejaveis'],
  GERAR_DESCRICAO: ['descricao'],
  SUGERIR_CARGOS: ['cargos_compativeis'],
  SUGERIR_CBOS: ['cbos_compativeis'],
  GERAR_REQUISITOS_OBRIGATORIOS: ['requisitos_obrigatorios'],
  GERAR_REQUISITOS_DESEJAVEIS: ['requisitos_desejaveis'],
};

const expected = actionFields[request.acao] ?? actionFields.GERAR_TODOS;
const hasSuggestion = expected.some((field) => {
  const value = suggestions[field];
  return Array.isArray(value) ? value.length > 0 : Boolean(value);
});

if (!hasSuggestion) {
  throw new Error('A IA não gerou uma sugestão utilizável com confiança suficiente para o campo solicitado.');
}

return [{
  json: {
    sucesso: true,
    acao: request.acao,
    sugestoes: suggestions,
    avisos: [
      'Revise todas as sugestões antes de aplicá-las.',
      'CBOs de baixa confiança foram descartados. Confirme código e título na consulta oficial do MTE.',
    ],
  },
}];
